import{_ as e,o,c as l,a2 as t}from"./chunks/framework.m9rfQn3T.js";const _=JSON.parse('{"title":"模块规范","description":"","frontmatter":{"title":"模块规范","date":"2021-11-23T21:21:55.000Z","permalink":"/pages/a7e7fa4fe512d/","categories":["面试题","JavaScript"],"tags":[null]},"headers":[],"relativePath":"10.面试题/30.JavaScript/60.模块规范.md","filePath":"10.面试题/30.JavaScript/60.模块规范.md","lastUpdated":1782538095000}'),i={name:"10.面试题/30.JavaScript/60.模块规范.md"};function p(r,a,m,n,s,d){return o(),l("div",null,[...a[0]||(a[0]=[t('<p>CommonJS/AMD/UMD/ES6 Module 这四种模块规范</p><ol><li><p>CommonJS 规范定义了模块应该怎样进行编写，从而各个模块系统之间可以进行相互操作。</p></li><li><p>CommonJS 不支持异步加载，因此异步模块定义（AMD）主要为了解决异步加载模块而提出。</p></li><li><p>通用模块定义（UMD）模式用于兼容 AMD 和 CommonJS 的规范。</p></li><li><p>CommonJS 规范用于运行时进行模块加载，ES6 模块化可以在编译阶段确定各个模块之间的依赖关系。</p></li></ol><p>&lt;!-- more --&gt;</p><h2 id="commonjs" tabindex="-1">Commonjs <a class="header-anchor" href="#commonjs" aria-label="Permalink to &quot;Commonjs&quot;">​</a></h2><p>特点</p><ul><li>一个文件就是一个模块</li><li>使用 require 载入模块，使用 module.exports 输出模块，因此各个模块间可以进行交互</li><li>不支持异步加载</li></ul><p>主要是 nodejs 使用的规范</p><h2 id="amd" tabindex="-1">AMD <a class="header-anchor" href="#amd" aria-label="Permalink to &quot;AMD&quot;">​</a></h2><p>异步定义模块，主要就是为了解决异步加载模块而提出</p><p>Requirejs 就是 AMD 的实现</p><h2 id="umd" tabindex="-1">UMD <a class="header-anchor" href="#umd" aria-label="Permalink to &quot;UMD&quot;">​</a></h2><p>兼容 AMD 和 Commonjs，并且支持了传统的全局变量模式</p><h2 id="es6" tabindex="-1">ES6 <a class="header-anchor" href="#es6" aria-label="Permalink to &quot;ES6&quot;">​</a></h2><p>相比于<code>运行时</code>进行加载的 CommonJS 规范，ES6 模块化主要是为了在<code>编译阶段</code>就可以确定各个模块之间的依赖关系</p><p>特点</p><ul><li>使用 es6 加载 export 导出</li><li>一个模块只会加载一次(Commonjs 也是一样)</li><li>导出的模块为变量引用，因此可以在内存中共享</li></ul><p>大部分是用 es6 模块，因为我们编译的时候需要使用 babel、webpack 等方式构建依赖树</p><p>es6 有兼容性问题，因此需要使用 babel 编译，以及 webpack 打包</p><p>CommonJS 导入的是导出值的拷贝，但导出值变化时，到导入值不会改变；而 ES6 Module 则是动态映射，会随着导出值的改变而变</p>',19)])])}const u=e(i,[["render",p]]);export{_ as __pageData,u as default};
